    #[test]
    fn optimized_visible_first_recalc_projects_only_viewport_upstream_cone() {
        let bounds = ExcelGridBounds {
            max_rows: 1_000,
            max_cols: 10,
        };
        let mut sheet = GridOptimizedSheet::new("book:default", "sheet:default", bounds);
        let dense_rect =
            GridRect::new("book:default", "sheet:default", 1, 1, 1_000, 8, bounds).unwrap();
        sheet
            .put_dense_number_region_with(dense_rect, |address| {
                f64::from(address.row) * 1000.0 + f64::from(address.col)
            })
            .unwrap();
        let formula_rect =
            GridRect::new("book:default", "sheet:default", 1, 9, 1_000, 10, bounds).unwrap();
        sheet
            .put_repeated_formula_region(
                formula_rect,
                GridFormulaCell::new("=RC[-1]*2", "excel.grid.v1:r1c1-template:RC[-1]*2")
                    .with_source_channel(FormulaChannelKind::WorksheetR1C1),
            )
            .unwrap();

        let visible_rect =
            GridRect::new("book:default", "sheet:default", 200, 10, 299, 10, bounds).unwrap();
        let (valuation, report) = sheet
            .recalculate_visible_rect_compact_with_oxfml(visible_rect.clone(), 1_000)
            .expect("visible viewport should be evaluable");
        let visible = valuation
            .tile_snapshot_report(visible_rect)
            .expect("visible viewport should be reportable");

        assert_eq!(report.visible_cell_count, 100);
        assert_eq!(report.visible_upstream_cell_count, 300);
        assert_eq!(report.dense_value_cells_projected, 100);
        assert_eq!(report.repeated_formula_cells_projected, 200);
        assert_eq!(report.cells_evaluated_before_visible_complete, 300);
        assert_eq!(report.formula_evaluations_before_visible_complete, 200);
        assert_eq!(report.full_recalc_occupied_cell_floor, 10_000);
        assert!(report.p16_visible_first_holds());
        assert_eq!(visible.subscribed_cell_count, 100);
        assert_eq!(visible.defined_cell_count, 100);
        assert_eq!(visible.dense_value_cells_visited, 100);
        assert_eq!(visible.sparse_value_cells_visited, 0);
        let row_250 = valuation.read_cell(&ExcelGridCellAddress::new(
            "book:default",
            "sheet:default",
            250,
            10,
        ));
        assert_eq!(number_from_calc_value(&row_250.computed), Some(1_000_032.0));
    }

    // C6 guard: `visible_same_row_left_upstream_rect` must size the upstream
    // cone from the COMPILED plan (matching
    // `try_evaluate_repeated_formula_visible_subrect`'s gate), not a literal
    // source_text comparison against "=RC[-1]*2". A whitespace variant of
    // the identical formula ("=RC[-1] * 2") compiles to the same plan and
    // must get the same cone; a text-equality gate would fail to widen the
    // cone, leaving the region's upstream input unprojected and its chained
    // values wrong (published as blank/zero).
    #[test]
    fn optimized_visible_first_recalc_projects_upstream_cone_for_whitespace_formula_variant() {
        let bounds = ExcelGridBounds {
            max_rows: 1_000,
            max_cols: 10,
        };
        let mut sheet = GridOptimizedSheet::new("book:default", "sheet:default", bounds);
        let dense_rect =
            GridRect::new("book:default", "sheet:default", 1, 1, 1_000, 8, bounds).unwrap();
        sheet
            .put_dense_number_region_with(dense_rect, |address| {
                f64::from(address.row) * 1000.0 + f64::from(address.col)
            })
            .unwrap();
        let formula_rect =
            GridRect::new("book:default", "sheet:default", 1, 9, 1_000, 10, bounds).unwrap();
        sheet
            .put_repeated_formula_region(
                formula_rect,
                GridFormulaCell::new(
                    "=RC[-1] * 2",
                    "excel.grid.v1:r1c1-template-whitespace:RC[-1] * 2",
                )
                .with_source_channel(FormulaChannelKind::WorksheetR1C1),
            )
            .unwrap();

        let visible_rect =
            GridRect::new("book:default", "sheet:default", 200, 10, 299, 10, bounds).unwrap();
        let (valuation, report) = sheet
            .recalculate_visible_rect_compact_with_oxfml(visible_rect, 1_000)
            .expect("visible viewport should be evaluable for a whitespace formula variant");

        // Same cone shape as the tight-source-text version above: the
        // upstream cone must widen to include the same-row-left dense
        // literal column even though the formula text has extra whitespace.
        assert_eq!(report.visible_upstream_cell_count, 300);
        assert_eq!(report.dense_value_cells_projected, 100);
        assert_eq!(report.repeated_formula_cells_projected, 200);

        let row_250 = valuation.read_cell(&ExcelGridCellAddress::new(
            "book:default",
            "sheet:default",
            250,
            10,
        ));
        assert_eq!(number_from_calc_value(&row_250.computed), Some(1_000_032.0));
    }

    #[test]
    fn optimized_visible_first_recalc_records_runtime_overlay_dependencies() {
        let mut sheet = optimized_sheet();
        let a1 = address(1, 1);
        let b1 = address(1, 2);
        let c1 = address(1, 3);
        sheet
            .set_literal(a1.clone(), CalcValue::number(42.0))
            .unwrap();
        sheet
            .set_literal(
                b1.clone(),
                CalcValue::text(ExcelText::from_interop_assignment("A1")),
            )
            .unwrap();
        sheet
            .set_formula(
                c1.clone(),
                GridFormulaCell::new(
                    "=SUM(INDIRECT(B1))",
                    "excel.grid.v1:optimized-visible-indirect:B1",
                ),
            )
            .unwrap();

        let visible_rect =
            GridRect::new("book:default", "sheet:default", 1, 1, 1, 3, bounds()).unwrap();
        let (valuation, report) = sheet
            .recalculate_visible_rect_compact_with_oxfml(visible_rect, 100)
            .expect("visible dynamic formula should evaluate and record overlay dependencies");

        assert_eq!(valuation.read_cell(&c1).computed, CalcValue::number(42.0));
        assert_eq!(report.formula_evaluations_before_visible_complete, 1);
        let graph = valuation.runtime_dependency_graph();
        assert_eq!(
            graph.dependencies_for_layer(GridDependencyLayer::Structural, &c1),
            set([b1])
        );
        assert_eq!(
            graph.dependencies_for_layer(GridDependencyLayer::CalcOverlay, &c1),
            set([a1.clone()])
        );
        assert_eq!(graph.dirty_closure([a1.clone()]), set([a1, c1]));
    }

    // C2 guard: `recalculate_visible_rect_compact_with_oxfml` must project
    // ALL in-cone literals (sparse literals AND dense-region subrects)
    // before evaluating any in-cone formula. A1 lives in a dense literal
    // region; B1 is a sparse formula reading it. Under the old
    // single-pass-over-sparse-points-then-dense-regions ordering, B1
    // (evaluated in the sparse-points loop) would read A1 before the dense
    // region's second loop ever projected it, computing from blank.
    #[test]
    fn optimized_visible_first_recalc_projects_dense_literal_before_incone_sparse_formula() {
        let mut sheet = optimized_sheet();
        let a1 = address(1, 1);
        let b1 = address(1, 2);
        sheet
            .put_dense_literal_region(
                GridRect::new("book:default", "sheet:default", 1, 1, 1, 1, bounds()).unwrap(),
                vec![CalcValue::number(10.0)],
            )
            .unwrap();
        sheet
            .set_formula(
                b1.clone(),
                GridFormulaCell::new("=A1+1", "excel.grid.v1:optimized-visible-dense-literal:A1"),
            )
            .unwrap();

        let visible_rect =
            GridRect::new("book:default", "sheet:default", 1, 1, 1, 2, bounds()).unwrap();
        let (valuation, _report) = sheet
            .recalculate_visible_rect_compact_with_oxfml(visible_rect, 100)
            .expect("visible rect covering a dense literal and a dependent sparse formula should evaluate");

        assert_eq!(valuation.read_cell(&b1).computed, CalcValue::number(11.0));

        let report = sheet
            .run_engine_mode_with_oxfml(GridEngineMode::Both, [a1, b1], 100)
            .expect("dense literal + dependent sparse formula should match the reference oracle");
        assert!(report.mismatches.is_empty());
    }

    // C3 guard: a visible-first (`GridOptimizedValuationCoverage::
    // VisibleProjection`) valuation only reflects an upstream cone. It must
    // never be silently trusted by dirty recalc (which would
    // under-recalculate everything outside the cone) or by warm-no-op
    // (which would hand back a partial valuation as if nothing changed).
    #[test]
    fn optimized_partial_visible_projection_valuation_is_never_silently_trusted() {
        let mut sheet = optimized_sheet();
        let a1 = address(1, 1);
        let b1 = address(1, 2);
        let far_cell = address(9, 1);
        sheet
            .set_literal(a1.clone(), CalcValue::number(1.0))
            .unwrap();
        sheet
            .set_formula(
                b1.clone(),
                GridFormulaCell::new("=A1+1", "excel.grid.v1:optimized-partial-coverage:A1"),
            )
            .unwrap();
        sheet
            .set_literal(far_cell.clone(), CalcValue::number(99.0))
            .unwrap();

        let visible_rect =
            GridRect::new("book:default", "sheet:default", 1, 1, 1, 2, bounds()).unwrap();
        let (partial_valuation, _) = sheet
            .recalculate_visible_rect_compact_with_oxfml(visible_rect, 100)
            .expect("visible-first recalc should succeed");
        assert!(!partial_valuation.is_full_coverage());
        assert!(matches!(
            partial_valuation.coverage(),
            GridOptimizedValuationCoverage::VisibleProjection { .. }
        ));
        // The partial valuation never even reached far_cell.
        assert_eq!(
            partial_valuation.read_cell(&far_cell).computed,
            CalcValue::empty()
        );

        // Dirty recalc must not seed from a partial valuation and trust it
        // as-is: it must escalate to a full mark-all instead, so far_cell
        // (outside the visible-first cone) is correctly populated.
        let (escalated_valuation, _escalated_report) = sheet
            .recalculate_dirty_compact_with_oxfml(
                &partial_valuation,
                [GridDirtySeed::Cell(a1.clone())],
                100,
            )
            .expect("dirty recalc fed a partial valuation should escalate to mark-all");
        assert!(escalated_valuation.is_full_coverage());
        assert_eq!(
            escalated_valuation.read_cell(&b1).computed,
            CalcValue::number(2.0)
        );
        assert_eq!(
            escalated_valuation.read_cell(&far_cell).computed,
            CalcValue::number(99.0)
        );

        // Warm no-op must never treat a partial valuation as a reusable
        // "nothing changed" cache hit.
        let cache = GridOptimizedWarmNoOpCache {
            token: sheet.warm_noop_token(100),
            valuation: partial_valuation,
            baseline_report: GridOptimizedRecalcReport::empty(),
        };
        assert!(
            sheet
                .recalculate_warm_noop_compact_with_oxfml(&cache)
                .is_none(),
            "a partial (visible-projection) valuation must never warm-skip"
        );
    }

    // ---- W062 R4.2: seeded optimized lane (consumer incremental wiring) ----

    /// The O(dirty cone) bar, evidenced by counters (D3 §6.5): a fixture of one
    /// literal root plus a chain of N formulas, recalculated once via the seeded
    /// lane (mark-all: `NoRetainedValuation`, `cells_evaluated` covers the whole
    /// authored sheet), then a single-cell edit re-recalculated via the seeded
    /// lane (incremental: `cells_evaluated` is the dirty cone, ≪ N).
    #[test]
    fn seeded_lane_single_edit_evaluates_only_the_dirty_cone() {
        // A1 = 1; B1 = A1+1; C1 = B1+1; … a straight chain so the dirty cone of
        // editing A1 is the whole chain, but editing the LAST cell's own literal
        // input touches only itself. We build two independent, unrelated chains so
        // an edit confined to one leaves the other untouched — the measurable gap.
        // Explicit A1-style references so each formula names the cell to its left
        // (col letters A..E for cols 1..5).
        let col_letter = |col: u32| ((b'A' + (col - 1) as u8) as char).to_string();
        let mut sheet = optimized_sheet();
        // Chain 1 (row 1): A1 literal, B1..E1 each = <left cell> + 1 (4 formulas).
        sheet
            .set_literal(address(1, 1), CalcValue::number(1.0))
            .unwrap();
        for col in 2..=5u32 {
            let left = format!("{}1", col_letter(col - 1));
            sheet
                .set_formula(
                    address(1, col),
                    GridFormulaCell::new(
                        format!("={left}+1"),
                        format!("excel.grid.v1:r4_2:chain1:c{col}"),
                    ),
                )
                .unwrap();
        }
        // Chain 2 (row 3): A3 literal, B3..E3 each = <left cell> + 1 (independent).
        sheet
            .set_literal(address(3, 1), CalcValue::number(100.0))
            .unwrap();
        for col in 2..=5u32 {
            let left = format!("{}3", col_letter(col - 1));
            sheet
                .set_formula(
                    address(3, col),
                    GridFormulaCell::new(
                        format!("={left}+1"),
                        format!("excel.grid.v1:r4_2:chain2:c{col}"),
                    ),
                )
                .unwrap();
        }

        let probes: Vec<_> = (1..=5u32)
            .map(|c| address(1, c))
            .chain((1..=5u32).map(|c| address(3, c)))
            .collect();

        // First recalc: no retained valuation ⇒ mark-all establishes the graph.
        let first = sheet
            .recalc_optimized_lane_seeded(None, false, true, [], probes.clone(), true, 1_000_000)
            .expect("first seeded recalc (mark-all) should succeed");
        assert_eq!(
            first.lane_outcome,
            GridSeededLaneOutcome::NoRetainedValuation
        );
        assert!(
            first.mismatches.is_empty(),
            "reference oracle lane must be clean"
        );
        assert!(first.reference_lane_ran);
        // Mark-all evaluates every formula cell: 8 formulas across both chains.
        let mark_all_formula_evals = first.optimized_recalc.formula_evaluations;
        assert_eq!(
            mark_all_formula_evals, 8,
            "mark-all evaluates all 8 authored formulas"
        );
        assert_eq!(
            first.valuation.read_cell(&address(1, 5)).computed,
            CalcValue::number(5.0)
        );
        assert_eq!(
            first.valuation.read_cell(&address(3, 5)).computed,
            CalcValue::number(104.0)
        );

        // Edit chain 2's ROOT literal A3: 100 -> 200. Dirty cone = chain 2 only
        // (its 4 formulas); chain 1 must not be re-evaluated.
        sheet
            .set_literal(address(3, 1), CalcValue::number(200.0))
            .unwrap();
        let second = sheet
            .recalc_optimized_lane_seeded(
                Some(&first.valuation),
                true, // basis matches
                true, // topology preserving (edits an existing literal)
                [GridDirtySeed::Cell(address(3, 1))],
                probes.clone(),
                true,
                1_000_000,
            )
            .expect("second seeded recalc (incremental) should succeed");
        assert_eq!(
            second.lane_outcome,
            GridSeededLaneOutcome::Incremental,
            "a basis-current, full-coverage, graph-installed retained valuation rides incremental"
        );
        assert!(second.lane_outcome.is_incremental());
        assert!(
            second.mismatches.is_empty(),
            "incremental result matches the reference oracle"
        );
        // O(dirty cone): only chain 2's 4 formulas re-evaluate, NOT all 8.
        assert_eq!(
            second.optimized_recalc.formula_evaluations, 4,
            "incremental edit re-evaluates only the dirty cone (chain 2), not O(authored)"
        );
        assert!(
            second.optimized_recalc.formula_evaluations < mark_all_formula_evals,
            "the dirty cone is strictly smaller than the authored formula count"
        );
        // Chain 2 reflects the edit; chain 1 is unchanged.
        assert_eq!(
            second.valuation.read_cell(&address(3, 5)).computed,
            CalcValue::number(204.0)
        );
        assert_eq!(
            second.valuation.read_cell(&address(1, 5)).computed,
            CalcValue::number(5.0)
        );
    }

    /// Escalation is typed and always to correctness (D3 §6.1). A `None` retained
    /// valuation escalates via `NoRetainedValuation`; a basis mismatch (the C6
    /// revision-navigation signal) escalates via `BasisMismatch`; both land on a
    /// full, full-coverage mark-all with correct values.
    #[test]
    fn seeded_lane_escalations_are_typed_and_correct() {
        let mut sheet = optimized_sheet();
        sheet
            .set_literal(address(1, 1), CalcValue::number(5.0))
            .unwrap();
        sheet
            .set_formula(
                address(1, 2),
                GridFormulaCell::new("=A1*2", "excel.grid.v1:r4_2:esc"),
            )
            .unwrap();
        let probes = vec![address(1, 1), address(1, 2)];

        // No retained valuation ⇒ NoRetainedValuation, mark-all.
        let base = sheet
            .recalc_optimized_lane_seeded(None, false, true, [], probes.clone(), true, 100)
            .unwrap();
        assert_eq!(
            base.lane_outcome,
            GridSeededLaneOutcome::NoRetainedValuation
        );
        assert!(base.valuation.is_full_coverage());
        assert_eq!(
            base.valuation.read_cell(&address(1, 2)).computed,
            CalcValue::number(10.0)
        );

        // A retained valuation present but basis_matches=false ⇒ BasisMismatch,
        // still escalates to mark-all with correct values (edit A1 5 -> 6).
        sheet
            .set_literal(address(1, 1), CalcValue::number(6.0))
            .unwrap();
        let escalated = sheet
            .recalc_optimized_lane_seeded(
                Some(&base.valuation),
                false, // basis mismatch: caller says the retained base is stale
                true,  // topology preserving
                [GridDirtySeed::Cell(address(1, 1))],
                probes.clone(),
                true,
                100,
            )
            .unwrap();
        assert_eq!(escalated.lane_outcome, GridSeededLaneOutcome::BasisMismatch);
        assert!(escalated.valuation.is_full_coverage());
        assert!(escalated.mismatches.is_empty());
        assert_eq!(
            escalated.valuation.read_cell(&address(1, 2)).computed,
            CalcValue::number(12.0)
        );

        // A basis-current retained valuation but topology_preserving=false (the
        // edit grew the sheet, e.g. a range fill) ⇒ TopologyGrowth, mark-all.
        let grown = sheet
            .recalc_optimized_lane_seeded(
                Some(&escalated.valuation),
                true,  // basis matches
                false, // topology grew: incremental dirty closure can't see new cells
                [GridDirtySeed::Cell(address(1, 1))],
                probes.clone(),
                true,
                100,
            )
            .unwrap();
        assert_eq!(grown.lane_outcome, GridSeededLaneOutcome::TopologyGrowth);
        assert!(!grown.lane_outcome.is_incremental());
        assert!(grown.valuation.is_full_coverage());
        assert!(grown.mismatches.is_empty());
    }

    /// W062 R4.8 (D3 §7): an injected [`WorkbookRecalcTick`] makes `NOW()`
    /// coherent across every cell of the sheet (one timestamp), makes `RAND()`
    /// deterministic and node-keyed, and — because BOTH the optimized lane and
    /// the reference oracle consume the SAME tick — leaves the differential
    /// exact-clean on the volatile cells (volatiles are compared, not excluded).
    #[test]
    fn injected_tick_makes_now_coherent_and_volatile_differential_clean() {
        let mut sheet = optimized_sheet();
        // Two `NOW()` cells (must read the SAME serial) and two `RAND()` cells
        // (deterministic, node-keyed, in range).
        for (row, col, text) in [
            (1, 1, "=NOW()"),
            (9, 5, "=NOW()"),
            (1, 2, "=RAND()"),
            (9, 4, "=RAND()"),
        ] {
            sheet
                .set_formula(
                    address(row, col),
                    GridFormulaCell::new(text, "excel.grid.v1:r4_8:tick"),
                )
                .unwrap();
        }
        // Inject a FIXED tick (no wall-clock dependence).
        let tick = WorkbookRecalcTick::new(99, 45_678.25, 0xC0FF_EE00);
        sheet.set_recalc_tick(tick);

        let probes = vec![address(1, 1), address(9, 5), address(1, 2), address(9, 4)];
        let report = sheet
            .recalc_optimized_lane_seeded(None, false, true, [], probes.clone(), true, 100)
            .unwrap();

        // Both `NOW()` cells read the tick's single coherent serial (compared on
        // the numeric core; `NOW()` carries a `DateLike` presentation hint).
        let now_a = report.valuation.read_cell(&address(1, 1)).computed;
        let now_b = report.valuation.read_cell(&address(9, 5)).computed;
        assert_eq!(now_a.core, CoreValue::Number(45_678.25));
        assert_eq!(
            now_b.core, now_a.core,
            "NOW() must be coherent across cells"
        );

        // Both `RAND()` cells are in range and DIFFER (distinct node keys).
        let rand_a = report.valuation.read_cell(&address(1, 2)).computed;
        let rand_b = report.valuation.read_cell(&address(9, 4)).computed;
        for value in [&rand_a, &rand_b] {
            match value.core {
                CoreValue::Number(n) => {
                    assert!((0.0..1.0).contains(&n), "RAND {n} out of range");
                }
                ref other => panic!("RAND() did not yield a number: {other:?}"),
            }
        }
        assert_ne!(rand_a, rand_b, "distinct nodes draw distinct RAND values");

        // The oracle lane ran and — sharing the same tick — the differential is
        // exact-clean on the volatile cells (they are compared, not excluded).
        assert!(report.reference_lane_ran);
        assert!(
            report.mismatches.is_empty(),
            "volatile differential mismatched: {:?}",
            report.mismatches
        );

        // Replay: the recalc report records the tick it observed (D3 §7), so a
        // replay can re-inject exactly this tick and reproduce the volatiles.
        assert_eq!(report.recalc_tick, Some(tick));

        // Determinism: a second recalc with the SAME tick reproduces the values.
        let mut sheet2 = optimized_sheet();
        for (row, col, text) in [(1, 1, "=NOW()"), (1, 2, "=RAND()")] {
            sheet2
                .set_formula(
                    address(row, col),
                    GridFormulaCell::new(text, "excel.grid.v1:r4_8:tick"),
                )
                .unwrap();
        }
        sheet2.set_recalc_tick(tick);
        let report2 = sheet2
            .recalc_optimized_lane_seeded(
                None,
                false,
                true,
                [],
                vec![address(1, 1), address(1, 2)],
                true,
                100,
            )
            .unwrap();
        assert_eq!(report2.valuation.read_cell(&address(1, 1)).computed, now_a);
        assert_eq!(report2.valuation.read_cell(&address(1, 2)).computed, rand_a);
    }

    /// W062 R4.8: permuting the evaluation worklist must not change any cell's
    /// `RAND()` value — draws are keyed on (rng_seed, node id), not on
    /// evaluation sequence (D3 §7 concurrency-prep property). Two sheets with
    /// the same authored `RAND()` cells in different insertion orders, under the
    /// same tick, produce identical per-cell values.
    #[test]
    fn rand_values_are_invariant_under_evaluation_order() {
        let tick = WorkbookRecalcTick::new(7, 0.0, 0x5EED_1234);
        let cells = [address(1, 1), address(2, 2), address(3, 3), address(4, 4)];

        let read_all = |insertion: &[ExcelGridCellAddress]| {
            let mut sheet = optimized_sheet();
            for addr in insertion {
                sheet
                    .set_formula(
                        addr.clone(),
                        GridFormulaCell::new("=RAND()", "excel.grid.v1:r4_8:order"),
                    )
                    .unwrap();
            }
            sheet.set_recalc_tick(tick);
            let report = sheet
                .recalc_optimized_lane_seeded(None, false, true, [], cells.to_vec(), false, 100)
                .unwrap();
            cells
                .iter()
                .map(|addr| report.valuation.read_cell(addr).computed)
                .collect::<Vec<_>>()
        };

        let forward = read_all(&cells);
        let mut reversed = cells.to_vec();
        reversed.reverse();
        let permuted = read_all(&reversed);

        assert_eq!(
            forward, permuted,
            "RAND values changed when evaluation order changed"
        );
    }

    /// The two remaining escalation variants, pinned directly (closing the
    /// `GridSeededLaneOutcome` coverage): a visible-first partial valuation
    /// escalates via `NotFullCoverage`, and a full-coverage valuation whose graph
    /// was never installed by a mark-all escalates via `GraphNotInstalled`. Both
    /// land on a correct full mark-all.
    #[test]
    fn seeded_lane_escalates_on_partial_coverage_and_uninstalled_graph() {
        let mut sheet = optimized_sheet();
        sheet
            .set_literal(address(1, 1), CalcValue::number(5.0))
            .unwrap();
        sheet
            .set_formula(
                address(1, 2),
                GridFormulaCell::new("=A1*2", "excel.grid.v1:r4_2:cov"),
            )
            .unwrap();
        let probes = vec![address(1, 1), address(1, 2)];

        // Visible-first recalc yields a partial (VisibleProjection) valuation.
        let visible_rect =
            GridRect::new("book:default", "sheet:default", 1, 1, 1, 1, bounds()).unwrap();
        let (partial, _) = sheet
            .recalculate_visible_rect_compact_with_oxfml(visible_rect, 100)
            .unwrap();
        assert!(!partial.is_full_coverage());
        let escalated = sheet
            .recalc_optimized_lane_seeded(
                Some(&partial),
                true, // basis matches
                true, // topology preserving
                [GridDirtySeed::Cell(address(1, 1))],
                probes.clone(),
                true,
                100,
            )
            .unwrap();
        assert_eq!(
            escalated.lane_outcome,
            GridSeededLaneOutcome::NotFullCoverage
        );
        assert!(escalated.valuation.is_full_coverage());
        assert!(escalated.mismatches.is_empty());
        assert_eq!(
            escalated.valuation.read_cell(&address(1, 2)).computed,
            CalcValue::number(10.0)
        );

        // A fresh (never mark-all'd) valuation is full-coverage but has no
        // installed dependency graph ⇒ GraphNotInstalled.
        let uninstalled = sheet.empty_valuation_with_committed_spill_state();
        assert!(uninstalled.is_full_coverage());
        let escalated = sheet
            .recalc_optimized_lane_seeded(
                Some(&uninstalled),
                true,
                true,
                [GridDirtySeed::Cell(address(1, 1))],
                probes,
                true,
                100,
            )
            .unwrap();
        assert_eq!(
            escalated.lane_outcome,
            GridSeededLaneOutcome::GraphNotInstalled
        );
        assert!(escalated.valuation.is_full_coverage());
        assert!(escalated.mismatches.is_empty());
        assert_eq!(
            escalated.valuation.read_cell(&address(1, 2)).computed,
            CalcValue::number(10.0)
        );
    }

    /// The engine-validation mode governs only the reference lane's per-recalc
    /// spend (D3 §6.4). `OptimizedOnly`/`DualValidatedSampled` skip the
    /// reference lane (empty `mismatches`, `reference_lane_ran == false`) while
    /// the optimized lane still computes correctly; `DualValidated` always runs
    /// it. The knob never weakens the optimized lane.
    #[test]
    fn validation_mode_governs_only_the_reference_lane() {
        // DualValidated runs every tick; OptimizedOnly never;
        // DualValidatedSampled{one_in:4} on 0,4,8… and not on 1..=3.
        assert!(GridEngineValidationMode::DualValidated.runs_reference_lane(0));
        assert!(GridEngineValidationMode::DualValidated.runs_reference_lane(7));
        assert!(!GridEngineValidationMode::OptimizedOnly.runs_reference_lane(0));
        let sampled = GridEngineValidationMode::DualValidatedSampled { one_in: 4 };
        assert!(sampled.runs_reference_lane(0));
        assert!(!sampled.runs_reference_lane(1));
        assert!(!sampled.runs_reference_lane(2));
        assert!(!sampled.runs_reference_lane(3));
        assert!(sampled.runs_reference_lane(4));
        assert!(sampled.runs_reference_lane(8));

        let mut sheet = optimized_sheet();
        sheet
            .set_literal(address(1, 1), CalcValue::number(3.0))
            .unwrap();
        sheet
            .set_formula(
                address(1, 2),
                GridFormulaCell::new("=A1+4", "excel.grid.v1:r4_2:policy"),
            )
            .unwrap();
        let probes = vec![address(1, 2)];

        // Reference lane OFF: no oracle comparison, but the optimized value is
        // still correct.
        let off = sheet
            .recalc_optimized_lane_seeded(None, false, true, [], probes.clone(), false, 100)
            .unwrap();
        assert!(!off.reference_lane_ran);
        assert!(off.mismatches.is_empty());
        assert_eq!(
            off.valuation.read_cell(&address(1, 2)).computed,
            CalcValue::number(7.0)
        );

        // Reference lane ON: oracle runs and is clean.
        let on = sheet
            .recalc_optimized_lane_seeded(None, false, true, [], probes, true, 100)
            .unwrap();
        assert!(on.reference_lane_ran);
        assert!(on.mismatches.is_empty());
    }

    // ---- W062 R4.3: the O(dirty cone) bar, evidenced by checked-in counters ----
    //
    // R4.2 proved the mechanism on a 2-chain toy (4-vs-8). R4.3 formalizes the
    // BAR (D3 §6.5): a representative fixture — several hundred authored cells,
    // layered dependency structure, several disjoint regions — with checked-in
    // expected-counter baselines showing that a single-cell edit costs
    // O(dirty cone), NOT O(authored cells). Several cone sizes (small, mid,
    // near-full-region) are each pinned to exact counters, the mark-all cost is
    // recorded alongside as the regression tripwire, and the incremental cost is
    // asserted strictly below mark-all by the structural margin. Escalation paths
    // (mark-all by design) are excluded from the bar.
    //
    // Checked-in counter baseline (LOCAL_EXECUTION_DOCTRINE — the numbers ARE the
    // baseline; a regression to mark-all flips these assertions):
    //
    //   Fixture: 400x26 sheet, three disjoint single-column regions.
    //     R1 (col A): A1 literal, A2..A200 = A<r-1>+1   (1 literal + 199 formulas)
    //     R2 (col C): C1 literal, C2..C50  = C<r-1>+2   (1 literal +  49 formulas)
    //     R3 (col E): E1 literal, E2       = E1*10      (1 literal +   1 formula )
    //   Authored formulas N_f = 199 + 49 + 1 = 249.  Authored cells = 252.
    //
    //   Recalc            | cells_evaluated | formula_evaluations
    //   ------------------+-----------------+--------------------
    //   mark-all (build)  |       252       |        249
    //   edit leaf A200    |         1       |          1   (1-cell cone)
    //   edit root C1      |        50       |         49   (mid cone: whole R2)
    //   edit root A1      |       200       |        199   (near-full: whole R1)
    //
    // Every incremental cone is strictly < the 249-formula mark-all cost; the
    // near-full cone (199) is bounded by |R1|, NOT by N_f — editing the deepest
    // region still leaves R2+R3 (50 formulas) untouched. Wall-time note: the
    // reference lane / differential (a known-W056 O(n^2) diagnostics term) is
    // held OFF here so the diagnostics-lane cost cannot mask the engine bar; the
    // bar asserts on ENGINE counters, never wall time.

    /// Bounds and column indices for the R4.3 dirty-cone fixture.
    const R43_MAX_ROWS: u32 = 400;
    const R43_MAX_COLS: u32 = 26;
    const R43_COL_A: u32 = 1; // deep chain (near-full-region cone)
    const R43_COL_C: u32 = 3; // mid chain (mid cone)
    const R43_COL_E: u32 = 5; // tiny region (small cone + cross-region tripwire)
    const R43_R1_DEPTH: u32 = 200; // A1..A200
    const R43_R2_DEPTH: u32 = 50; //  C1..C50

    fn r43_bounds() -> ExcelGridBounds {
        ExcelGridBounds {
            max_rows: R43_MAX_ROWS,
            max_cols: R43_MAX_COLS,
        }
    }

    fn r43_address(row: u32, col: u32) -> ExcelGridCellAddress {
        ExcelGridCellAddress::new("book:default", "sheet:default", row, col)
    }

    /// One-letter column label (cols 1..=26 -> A..=Z). The fixture keeps every
    /// region in a single column so precedent references stay single-letter and
    /// chain depth lives on the (multi-digit) row axis.
    fn r43_col_letter(col: u32) -> char {
        (b'A' + (col - 1) as u8) as char
    }

    /// Build the representative dirty-cone fixture: three disjoint single-column
    /// chains rooted at a literal. Regions share no precedents, so an edit
    /// confined to one region can never dirty another — the cross-region
    /// tripwire the bar rests on.
    fn r43_dirty_cone_sheet() -> GridOptimizedSheet {
        let mut sheet = GridOptimizedSheet::new("book:default", "sheet:default", r43_bounds());

        // Region 1 (col A): deep chain, near-full-region cone source.
        sheet
            .set_literal(r43_address(1, R43_COL_A), CalcValue::number(1.0))
            .unwrap();
        for row in 2..=R43_R1_DEPTH {
            let letter = r43_col_letter(R43_COL_A);
            sheet
                .set_formula(
                    r43_address(row, R43_COL_A),
                    GridFormulaCell::new(
                        format!("={letter}{}+1", row - 1),
                        format!("excel.grid.v1:r4_3:r1:r{row}"),
                    ),
                )
                .unwrap();
        }

        // Region 2 (col C): mid chain, mid cone source.
        sheet
            .set_literal(r43_address(1, R43_COL_C), CalcValue::number(10.0))
            .unwrap();
        for row in 2..=R43_R2_DEPTH {
            let letter = r43_col_letter(R43_COL_C);
            sheet
                .set_formula(
                    r43_address(row, R43_COL_C),
                    GridFormulaCell::new(
                        format!("={letter}{}+2", row - 1),
                        format!("excel.grid.v1:r4_3:r2:r{row}"),
                    ),
                )
                .unwrap();
        }

        // Region 3 (col E): tiny region, small cone source + tripwire sentinel.
        sheet
            .set_literal(r43_address(1, R43_COL_E), CalcValue::number(7.0))
            .unwrap();
        sheet
            .set_formula(
                r43_address(2, R43_COL_E),
                GridFormulaCell::new("=E1*10", "excel.grid.v1:r4_3:r3:leaf"),
            )
            .unwrap();

        sheet
    }

    /// Probes covering every region's leaf (and the tripwire sentinel E2) so the
    /// reference oracle, when run, compares the whole fixture.
    fn r43_probes() -> Vec<ExcelGridCellAddress> {
        vec![
            r43_address(R43_R1_DEPTH, R43_COL_A), // A200
            r43_address(R43_R2_DEPTH, R43_COL_C), // C50
            r43_address(2, R43_COL_E),            // E2
        ]
    }

    /// The O(dirty cone) BAR (D3 §6.5). Build the fixture (mark-all, recording
    /// the authored-cell cost as the tripwire baseline), then perform three
    /// single-cell edits of increasing cone size and pin each to its EXACT
    /// engine counters — proving edit cost scales with the dirty cone, not the
    /// authored-cell count. The differential/reference lane is held OFF so the
    /// known-W056 O(n^2) diagnostics term cannot mask the engine bar.
    #[test]
    fn dirty_cone_bar_single_edit_scales_with_cone_not_authored_cells() {
        let mut sheet = r43_dirty_cone_sheet();
        let probes = r43_probes();

        // --- Build recalc: mark-all establishes the graph + retained valuation.
        // Its cost IS the regression tripwire: every incremental cone below must
        // come in strictly under these numbers by the structural margin.
        let build = sheet
            .recalc_optimized_lane_seeded(None, false, true, [], probes.clone(), false, 1_000_000)
            .expect("build (mark-all) seeded recalc should succeed");
        assert_eq!(
            build.lane_outcome,
            GridSeededLaneOutcome::NoRetainedValuation,
            "first recalc has no retained valuation -> mark-all"
        );
        // CHECKED-IN mark-all baseline (the tripwire).
        const MARK_ALL_CELLS_EVALUATED: u64 = 252;
        const MARK_ALL_FORMULA_EVALUATIONS: u64 = 249;
        assert_eq!(
            build.optimized_recalc.cells_evaluated, MARK_ALL_CELLS_EVALUATED,
            "mark-all evaluates every authored cell (252 = 249 formulas + 3 literals)"
        );
        assert_eq!(
            build.optimized_recalc.formula_evaluations, MARK_ALL_FORMULA_EVALUATIONS,
            "mark-all evaluates all 249 authored formulas"
        );
        // Sanity: the fixture computed correctly across all three regions.
        assert_eq!(
            build
                .valuation
                .read_cell(&r43_address(R43_R1_DEPTH, R43_COL_A))
                .computed,
            CalcValue::number(200.0) // A1=1, +1 per step, depth 200
        );
        assert_eq!(
            build
                .valuation
                .read_cell(&r43_address(R43_R2_DEPTH, R43_COL_C))
                .computed,
            CalcValue::number(108.0) // C1=10, +2 * 49 steps
        );
        assert_eq!(
            build
                .valuation
                .read_cell(&r43_address(2, R43_COL_E))
                .computed,
            CalcValue::number(70.0)
        );

        // --- Small cone: re-author the DEEPEST leaf A200 (a topology-preserving
        // same-address formula overwrite). Nothing depends on A200, so its dirty
        // cone is exactly itself: 1 cell, 1 formula evaluation.
        let leaf_letter = r43_col_letter(R43_COL_A);
        sheet
            .set_formula(
                r43_address(R43_R1_DEPTH, R43_COL_A),
                GridFormulaCell::new(
                    format!("={leaf_letter}{}+5", R43_R1_DEPTH - 1),
                    format!("excel.grid.v1:r4_3:r1:r{}", R43_R1_DEPTH),
                ),
            )
            .unwrap();
        let small = sheet
            .recalc_optimized_lane_seeded(
                Some(&build.valuation),
                true,
                true,
                [GridDirtySeed::Cell(r43_address(R43_R1_DEPTH, R43_COL_A))],
                probes.clone(),
                false,
                1_000_000,
            )
            .expect("small-cone incremental recalc should succeed");
        assert_eq!(small.lane_outcome, GridSeededLaneOutcome::Incremental);
        // CHECKED-IN small-cone baseline.
        const SMALL_CONE_CELLS_EVALUATED: u64 = 1;
        const SMALL_CONE_FORMULA_EVALUATIONS: u64 = 1;
        assert_eq!(
            small.optimized_recalc.cells_evaluated, SMALL_CONE_CELLS_EVALUATED,
            "editing a leaf re-evaluates only itself"
        );
        assert_eq!(
            small.optimized_recalc.formula_evaluations,
            SMALL_CONE_FORMULA_EVALUATIONS
        );
        // Value reflects the re-authored formula (A199=199, +5).
        assert_eq!(
            small
                .valuation
                .read_cell(&r43_address(R43_R1_DEPTH, R43_COL_A))
                .computed,
            CalcValue::number(204.0)
        );

        // --- Mid cone: edit region 2's ROOT literal C1. Dirty cone = all of R2
        // (49 formulas + the edited literal = 50 cells). R1 and R3 untouched.
        sheet
            .set_literal(r43_address(1, R43_COL_C), CalcValue::number(1000.0))
            .unwrap();
        let mid = sheet
            .recalc_optimized_lane_seeded(
                Some(&small.valuation),
                true,
                true,
                [GridDirtySeed::Cell(r43_address(1, R43_COL_C))],
                probes.clone(),
                false,
                1_000_000,
            )
            .expect("mid-cone incremental recalc should succeed");
        assert_eq!(mid.lane_outcome, GridSeededLaneOutcome::Incremental);
        // CHECKED-IN mid-cone baseline.
        const MID_CONE_CELLS_EVALUATED: u64 = 50;
        const MID_CONE_FORMULA_EVALUATIONS: u64 = 49;
        assert_eq!(
            mid.optimized_recalc.cells_evaluated, MID_CONE_CELLS_EVALUATED,
            "editing R2's root re-evaluates all of R2 (50 cells), nothing else"
        );
        assert_eq!(
            mid.optimized_recalc.formula_evaluations,
            MID_CONE_FORMULA_EVALUATIONS
        );
        assert_eq!(
            mid.valuation
                .read_cell(&r43_address(R43_R2_DEPTH, R43_COL_C))
                .computed,
            CalcValue::number(1098.0) // C1=1000, +2 * 49
        );

        // --- Near-full-region cone: edit region 1's ROOT literal A1. Dirty cone
        // = all of R1 (199 formulas + the literal = 200 cells). This is the
        // largest single-edit cone, yet it is bounded by |R1|, NOT by N_f: R2+R3
        // (50 formulas) are still never touched — that gap is the whole point.
        sheet
            .set_literal(r43_address(1, R43_COL_A), CalcValue::number(1000.0))
            .unwrap();
        let near_full = sheet
            .recalc_optimized_lane_seeded(
                Some(&mid.valuation),
                true,
                true,
                [GridDirtySeed::Cell(r43_address(1, R43_COL_A))],
                probes.clone(),
                false,
                1_000_000,
            )
            .expect("near-full-cone incremental recalc should succeed");
        assert_eq!(near_full.lane_outcome, GridSeededLaneOutcome::Incremental);
        // CHECKED-IN near-full-cone baseline.
        const NEAR_FULL_CONE_CELLS_EVALUATED: u64 = 200;
        const NEAR_FULL_CONE_FORMULA_EVALUATIONS: u64 = 199;
        assert_eq!(
            near_full.optimized_recalc.cells_evaluated, NEAR_FULL_CONE_CELLS_EVALUATED,
            "editing R1's root re-evaluates all of R1 (200 cells), nothing else"
        );
        assert_eq!(
            near_full.optimized_recalc.formula_evaluations,
            NEAR_FULL_CONE_FORMULA_EVALUATIONS
        );

        // === THE BAR ===
        // Every incremental cone is strictly below the mark-all tripwire, and the
        // largest cone is bounded by its region, not by the authored-formula
        // count. All comparisons run on RUNTIME counters (the per-recalc reports),
        // not on the baseline consts, so a regression to mark-all blows every one
        // of these even if someone "updates" the consts above.
        let mark_all_measured = build.optimized_recalc.formula_evaluations;
        for (label, cone) in [
            ("small", small.optimized_recalc.formula_evaluations),
            ("mid", mid.optimized_recalc.formula_evaluations),
            ("near-full", near_full.optimized_recalc.formula_evaluations),
        ] {
            assert!(
                cone < mark_all_measured,
                "{label} cone ({cone}) must be strictly below mark-all ({mark_all_measured})"
            );
        }
        // The structural margin, measured: even the near-full cone leaves R2+R3's
        // 50 formulas unevaluated. If the consumer regressed to mark-all, the
        // near-full recalc would report N_f (249) formula evaluations and this
        // margin would collapse to 0.
        let structural_margin =
            mark_all_measured.saturating_sub(near_full.optimized_recalc.formula_evaluations);
        assert_eq!(
            structural_margin, 50,
            "the near-full cone must fall short of mark-all by exactly R2+R3's \
             formula count (a regression to mark-all collapses this margin to 0)"
        );
    }

    /// Cross-region tripwire (D3 §6.5 (c)): an edit confined to one region must
    /// leave every OTHER region's values byte-identical — proving the cone is
    /// genuinely scoped, not merely "fewer evaluations". Also confirms the bar
    /// holds when the reference oracle IS run (differential clean) — i.e. the
    /// incremental cone is not trading correctness for cheapness.
    #[test]
    fn dirty_cone_edit_leaves_other_regions_untouched_and_differential_clean() {
        let mut sheet = r43_dirty_cone_sheet();
        let probes = r43_probes();

        // Build with the reference oracle ON: mark-all is differentially clean.
        let build = sheet
            .recalc_optimized_lane_seeded(None, false, true, [], probes.clone(), true, 1_000_000)
            .expect("build should succeed");
        assert!(build.reference_lane_ran);
        assert!(
            build.mismatches.is_empty(),
            "mark-all build matches the reference oracle"
        );
        let r1_leaf_before = build
            .valuation
            .read_cell(&r43_address(R43_R1_DEPTH, R43_COL_A))
            .computed;
        let r3_leaf_before = build
            .valuation
            .read_cell(&r43_address(2, R43_COL_E))
            .computed;

        // Edit region 2's root; run the reference oracle to prove the incremental
        // cone is correct, not just small.
        sheet
            .set_literal(r43_address(1, R43_COL_C), CalcValue::number(5000.0))
            .unwrap();
        let edited = sheet
            .recalc_optimized_lane_seeded(
                Some(&build.valuation),
                true,
                true,
                [GridDirtySeed::Cell(r43_address(1, R43_COL_C))],
                probes,
                true,
                1_000_000,
            )
            .expect("region-2 incremental recalc should succeed");
        assert_eq!(edited.lane_outcome, GridSeededLaneOutcome::Incremental);
        assert!(
            edited.reference_lane_ran && edited.mismatches.is_empty(),
            "incremental cone matches the reference oracle exactly (correct, not just cheap)"
        );
        // Region 2 updated…
        assert_eq!(
            edited
                .valuation
                .read_cell(&r43_address(R43_R2_DEPTH, R43_COL_C))
                .computed,
            CalcValue::number(5098.0)
        );
        // …while regions 1 and 3 are byte-identical to before the edit.
        assert_eq!(
            edited
                .valuation
                .read_cell(&r43_address(R43_R1_DEPTH, R43_COL_A))
                .computed,
            r1_leaf_before,
            "an R2 edit must not disturb R1"
        );
        assert_eq!(
            edited
                .valuation
                .read_cell(&r43_address(2, R43_COL_E))
                .computed,
            r3_leaf_before,
            "an R2 edit must not disturb R3 (cross-region tripwire)"
        );
        // And the cone stayed O(R2): 49 formulas, not N_f.
        assert_eq!(edited.optimized_recalc.formula_evaluations, 49);
    }

    #[test]
    fn optimized_grid_spill_blockage_probe_skips_empty_extent_cells() {
        let large_bounds = ExcelGridBounds {
            max_rows: 3_000,
            max_cols: 3,
        };
        let sheet = GridOptimizedSheet::new("book:default", "sheet:default", large_bounds);
        let anchor = ExcelGridCellAddress::new("book:default", "sheet:default", 1, 1);
        let extent = GridRect::new(
            "book:default",
            "sheet:default",
            1,
            1,
            3_000,
            1,
            large_bounds,
        )
        .unwrap();

        let report = sheet
            .optimized_spill_blockage_probe_report(&anchor, &extent)
            .expect("empty spill extent should be probeable");

        assert!(!report.blocked);
        assert_eq!(report.extent_cell_count, 3_000);
        assert_eq!(report.naive_extent_cell_probe_floor, 3_000);
        assert_eq!(report.compact_blocker_probe_count(), 0);
    }

    #[test]
    fn optimized_grid_spill_blockage_probe_finds_sparse_blocker_without_extent_scan() {
        let large_bounds = ExcelGridBounds {
            max_rows: 3_000,
            max_cols: 3,
        };
        let mut sheet = GridOptimizedSheet::new("book:default", "sheet:default", large_bounds);
        let anchor = ExcelGridCellAddress::new("book:default", "sheet:default", 1, 1);
        let extent = GridRect::new(
            "book:default",
            "sheet:default",
            1,
            1,
            3_000,
            1,
            large_bounds,
        )
        .unwrap();
        sheet
            .set_literal(
                ExcelGridCellAddress::new("book:default", "sheet:default", 3_000, 1),
                CalcValue::number(99.0),
            )
            .unwrap();

        let report = sheet
            .optimized_spill_blockage_probe_report(&anchor, &extent)
            .expect("sparse blocker should be probeable");

        assert!(report.blocked);
        assert_eq!(report.extent_cell_count, 3_000);
        assert_eq!(report.sparse_point_candidates, 1);
        assert_eq!(report.compact_blocker_probe_count(), 1);
        assert!(
            report.compact_blocker_probe_count() < report.naive_extent_cell_probe_floor as usize
        );
    }

    #[test]
    fn overlay_set_blockage_probe_matches_legacy_probe() {
        // OVL-2 equivalence proof: the unified overlay-set probe produces a
        // byte-identical blockage report to the legacy per-type probe across a
        // corpus exercising every candidate category (table feature, merged,
        // own-spill skip, blocked-formula anchor-containment, unblocked spill,
        // sparse payload, and an unblocked extent).
        use crate::grid::authored::GridFormulaCell;

        let bounds = ExcelGridBounds {
            max_rows: 100,
            max_cols: 12,
        };
        let addr = |row, col| ExcelGridCellAddress::new("book:default", "sheet:default", row, col);
        let rect = |top, left, bottom, right| {
            GridRect::new(
                "book:default",
                "sheet:default",
                top,
                left,
                bottom,
                right,
                bounds,
            )
            .unwrap()
        };

        let mut sheet = GridOptimizedSheet::new("book:default", "sheet:default", bounds);
        // A table A1:C5 (set_table_overlay also installs a "table-overlay"
        // feature-rendered region over the range).
        sheet
            .set_table_overlay(
                GridTableOverlay::new(
                    "t",
                    "T",
                    rect(1, 1, 5, 3),
                    vec![GridTableColumn::new("t:c", "C", 1, rect(2, 1, 5, 3))],
                )
                .with_header_rect(rect(1, 1, 1, 3)),
            )
            .unwrap();
        // A merged region E1:F2 and a sparse literal at E10.
        sheet.add_merged_region(rect(1, 5, 2, 6)).unwrap();
        sheet
            .set_literal(addr(10, 5), CalcValue::number(1.0))
            .unwrap();
        // A blocked spill anchored at a formula cell J1 (extent J1:J4), and an
        // unblocked spill anchored at H1 (extent H1:H4).
        sheet
            .set_formula(
                addr(1, 10),
                GridFormulaCell::new("=A1", "excel.grid.v1:cell:R[0]C[-9]"),
            )
            .unwrap();
        sheet
            .set_spill_fact(GridSpillFact {
                anchor: addr(1, 10),
                extent: rect(1, 10, 4, 10),
                blocked: true,
            })
            .unwrap();
        sheet
            .set_spill_fact(GridSpillFact {
                anchor: addr(1, 8),
                extent: rect(1, 8, 4, 8),
                blocked: false,
            })
            .unwrap();

        let facts = sheet.spill_facts().clone();
        let probes = [
            (addr(20, 1), rect(20, 1, 24, 3)), // unblocked
            (addr(1, 1), rect(1, 1, 10, 3)),   // table feature region
            (addr(5, 5), rect(1, 5, 5, 6)),    // merged region
            (addr(1, 8), rect(1, 8, 4, 8)),    // own unblocked spill -> skipped
            (addr(2, 10), rect(2, 10, 3, 10)), // inside blocked spill -> pre-pass
            (addr(10, 8), rect(1, 8, 8, 8)),   // unblocked spill blocks
            (addr(8, 5), rect(8, 5, 12, 6)),   // sparse payload at E10
        ];

        let mut saw_blocked = false;
        let mut saw_unblocked = false;
        for (anchor, extent) in &probes {
            let legacy = sheet
                .optimized_spill_blockage_probe_report_with_facts(anchor, extent, &facts)
                .unwrap();
            let unified = sheet
                .overlay_set_blockage_probe(anchor, extent, &facts)
                .unwrap();
            assert_eq!(
                legacy.blocked, unified.blocked,
                "blocked verdict diverged at anchor {anchor:?}"
            );
            assert_eq!(
                legacy.sparse_point_candidates,
                unified.sparse_point_candidates
            );
            assert_eq!(
                legacy.dense_value_region_candidates,
                unified.dense_value_region_candidates
            );
            assert_eq!(
                legacy.repeated_formula_region_candidates,
                unified.repeated_formula_region_candidates
            );
            assert_eq!(
                legacy.merged_region_candidates,
                unified.merged_region_candidates
            );
            assert_eq!(
                legacy.feature_rendered_region_candidates,
                unified.feature_rendered_region_candidates
            );
            assert_eq!(
                legacy.blocked_formula_spill_fact_candidates,
                unified.blocked_formula_spill_fact_candidates
            );
            assert_eq!(
                legacy.unblocked_spill_fact_candidates,
                unified.unblocked_spill_fact_candidates
            );
            assert_eq!(legacy.extent_cell_count, unified.extent_cell_count);
            assert_eq!(
                legacy.naive_extent_cell_probe_floor,
                unified.naive_extent_cell_probe_floor
            );
            saw_blocked |= unified.blocked;
            saw_unblocked |= !unified.blocked;
        }
        assert!(
            saw_blocked && saw_unblocked,
            "the corpus must exercise both blocked and unblocked outcomes"
        );
    }

    #[test]
    fn grid_overlay_methods_forward_to_legacy_per_type_behaviour() {
        let bounds = ExcelGridBounds {
            max_rows: 100,
            max_cols: 12,
        };
        let addr = |row, col| ExcelGridCellAddress::new("book:default", "sheet:default", row, col);
        let rect = |top, left, bottom, right| {
            GridRect::new(
                "book:default",
                "sheet:default",
                top,
                left,
                bottom,
                right,
                bounds,
            )
            .unwrap()
        };
        // Insert 2 rows before row 3: rows 1-2 hold, rows 3+ shift down by 2.
        let edit = GridAxisEdit::insert_rows(3, 2);

        // Table: the range, header, and column bands all transform.
        let table = GridTableOverlay::new(
            "t",
            "T",
            rect(1, 1, 5, 3),
            vec![GridTableColumn::new("t:c", "C", 1, rect(2, 1, 5, 3))],
        )
        .with_header_rect(rect(1, 1, 1, 3));
        let GridOverlay::Table(transformed_table) = GridOverlay::Table(table.clone())
            .transform_for_axis_edit(edit, bounds)
            .unwrap()
            .expect("table survives the insert")
        else {
            panic!("expected a table overlay");
        };
        assert_eq!(transformed_table.table_range, rect(1, 1, 7, 3));
        assert_eq!(transformed_table.header_rect, Some(rect(1, 1, 1, 3)));
        assert_eq!(transformed_table.columns[0].data_rect, rect(2, 1, 7, 3));

        // Merged region wholly above the insertion point is unchanged.
        let GridOverlay::Merged(transformed_merged) = GridOverlay::Merged(GridMergedRegion {
            rect: rect(1, 5, 2, 6),
        })
        .transform_for_axis_edit(edit, bounds)
        .unwrap()
        .expect("merge survives") else {
            panic!("expected a merged overlay");
        };
        assert_eq!(transformed_merged.rect, rect(1, 5, 2, 6));

        // Spill: anchor above the insert holds; the extent grows by the inserted rows.
        let GridOverlay::Spill(transformed_spill) = GridOverlay::Spill(GridSpillFact {
            anchor: addr(1, 8),
            extent: rect(1, 8, 4, 8),
            blocked: false,
        })
        .transform_for_axis_edit(edit, bounds)
        .unwrap()
        .expect("spill survives") else {
            panic!("expected a spill overlay");
        };
        assert_eq!(transformed_spill.anchor, addr(1, 8));
        assert_eq!(transformed_spill.extent, rect(1, 8, 6, 8));
        assert!(!transformed_spill.blocked);

        // admit_axis_edit: a pivot feature refuses an intersecting edit (with the
        // legacy detail string); a table-overlay feature admits it.
        let pivot = GridOverlay::FeatureRendered(FeatureRenderedRegion {
            rect: rect(1, 1, 5, 3),
            feature_kind: "pivot".to_string(),
            needs_refresh: false,
        });
        match pivot.admit_axis_edit(edit).unwrap() {
            EditAdmission::Refuse { detail } => {
                assert!(detail.contains("edit intersects claimed region R1C1:R5C3"));
            }
            EditAdmission::Allow => panic!("a pivot feature must refuse an intersecting edit"),
        }
        let table_feature = GridOverlay::FeatureRendered(FeatureRenderedRegion {
            rect: rect(1, 1, 5, 3),
            feature_kind: "table-overlay".to_string(),
            needs_refresh: false,
        });
        assert_eq!(
            table_feature.admit_axis_edit(edit).unwrap(),
            EditAdmission::Allow
        );

        // Kind discriminants and blocks_spill semantics.
        assert_eq!(
            GridOverlay::Merged(GridMergedRegion {
                rect: rect(1, 5, 2, 6)
            })
            .kind(),
            OverlayKind::Merged
        );
        assert_eq!(GridOverlay::Table(table).blocks_spill(), SpillBlock::None);
        assert_eq!(
            GridOverlay::Merged(GridMergedRegion {
                rect: rect(1, 5, 2, 6)
            })
            .blocks_spill(),
            SpillBlock::Hard
        );
        assert_eq!(
            GridOverlay::Spill(GridSpillFact {
                anchor: addr(1, 8),
                extent: rect(1, 8, 4, 8),
                blocked: true,
            })
            .blocks_spill(),
            SpillBlock::None
        );
    }

    #[test]
    fn grid_overlay_extension_seam_is_inert_yet_carries_active_policy() {
        let bounds = ExcelGridBounds {
            max_rows: 100,
            max_cols: 12,
        };
        let rect = |top, left, bottom, right| {
            GridRect::new(
                "book:default",
                "sheet:default",
                top,
                left,
                bottom,
                right,
                bounds,
            )
            .unwrap()
        };
        // Insert 2 rows before row 3: rows 1-2 hold, rows 3+ shift down by 2.
        let edit = GridAxisEdit::insert_rows(3, 2);

        // An inert extension - one per reserved seam kind - is a blockage and
        // admission no-op (OVL-6 invariant: Δ == ∅), even for an edit that
        // intersects its claimed rect.
        let claimed = rect(1, 1, 5, 3);
        for kind_tag in [
            OverlayKind::Cse,
            OverlayKind::ConditionalFormat,
            OverlayKind::RichObject,
            OverlayKind::Extension,
        ] {
            let inert = GridOverlay::Extension(GridOverlayExtension {
                kind_tag,
                claimed_rect: claimed.clone(),
                block_mode: SpillBlock::None,
                refuses_axis_edit: false,
                payload: String::new(),
            });
            assert_eq!(inert.kind(), kind_tag);
            assert_eq!(inert.claimed_rect(), &claimed);
            assert_eq!(inert.claimed_rects(), vec![&claimed]);
            assert_eq!(inert.blocks_spill(), SpillBlock::None);
            assert_eq!(inert.admit_axis_edit(edit).unwrap(), EditAdmission::Allow);
        }

        // The seam still carries a real rect transform: an intersecting insert
        // grows the claimed rect; every other field is preserved verbatim.
        let extension = GridOverlay::Extension(GridOverlayExtension {
            kind_tag: OverlayKind::ConditionalFormat,
            claimed_rect: rect(1, 1, 5, 3),
            block_mode: SpillBlock::None,
            refuses_axis_edit: false,
            payload: "cf:run-7".to_string(),
        });
        let GridOverlay::Extension(transformed) = extension
            .transform_for_axis_edit(edit, bounds)
            .unwrap()
            .expect("extension survives the insert")
        else {
            panic!("expected an extension overlay");
        };
        assert_eq!(transformed.claimed_rect, rect(1, 1, 7, 3));
        assert_eq!(transformed.kind_tag, OverlayKind::ConditionalFormat);
        assert_eq!(transformed.block_mode, SpillBlock::None);
        assert!(!transformed.refuses_axis_edit);
        assert_eq!(transformed.payload, "cf:run-7");

        // A deletion that swallows the whole rect drops the extension.
        assert!(
            GridOverlay::Extension(GridOverlayExtension {
                kind_tag: OverlayKind::Extension,
                claimed_rect: rect(1, 1, 5, 3),
                block_mode: SpillBlock::None,
                refuses_axis_edit: false,
                payload: String::new(),
            })
            .transform_for_axis_edit(GridAxisEdit::delete_rows(1, 5), bounds)
            .unwrap()
            .is_none()
        );

        // Forward-looking: a non-inert extension reports its own policy -
        // block_mode drives blocks_spill, and refuses_axis_edit refuses an
        // intersecting edit (with the legacy detail string) while still
        // admitting a disjoint one.
        let active = GridOverlay::Extension(GridOverlayExtension {
            kind_tag: OverlayKind::Cse,
            claimed_rect: rect(2, 2, 4, 4),
            block_mode: SpillBlock::Hard,
            refuses_axis_edit: true,
            payload: String::new(),
        });
        assert_eq!(active.blocks_spill(), SpillBlock::Hard);
        match active.admit_axis_edit(edit).unwrap() {
            EditAdmission::Refuse { detail } => {
                assert!(detail.contains("edit intersects claimed region R2C2:R4C4"));
            }
            EditAdmission::Allow => panic!("a refusing extension must refuse an intersecting edit"),
        }
        assert_eq!(
            active
                .admit_axis_edit(GridAxisEdit::insert_rows(9, 1))
                .unwrap(),
            EditAdmission::Allow,
            "a refusing extension still admits a disjoint edit"
        );
    }

    #[test]
    fn apply_axis_edit_unified_loop_preserves_counters_and_fail_fast() {
        let bounds = ExcelGridBounds {
            max_rows: 100,
            max_cols: 12,
        };
        let addr = |row, col| ExcelGridCellAddress::new("book:default", "sheet:default", row, col);
        let rect = |top, left, bottom, right| {
            GridRect::new(
                "book:default",
                "sheet:default",
                top,
                left,
                bottom,
                right,
                bounds,
            )
            .unwrap()
        };
        // A sheet carrying every overlay kind: a table A1:C5 (which also installs
        // a "table-overlay" feature region), a merged region E1:F2, a refusing
        // "pivot" feature H1:J3, and a spill anchored at L1.
        let build_sheet = || {
            let mut sheet = GridOptimizedSheet::new("book:default", "sheet:default", bounds);
            sheet
                .set_table_overlay(GridTableOverlay::new(
                    "t",
                    "T",
                    rect(1, 1, 5, 3),
                    vec![GridTableColumn::new("t:c", "C", 1, rect(2, 1, 5, 3))],
                ))
                .unwrap();
            sheet.add_merged_region(rect(1, 5, 2, 6)).unwrap();
            sheet
                .add_feature_rendered_region(rect(1, 8, 3, 10), "pivot", false)
                .unwrap();
            sheet
                .set_spill_fact(GridSpillFact {
                    anchor: addr(1, 12),
                    extent: rect(1, 12, 4, 12),
                    blocked: false,
                })
                .unwrap();
            sheet
        };

        // Insert a row before row 1: every overlay shifts down, and only the pivot
        // (which marks-refresh-on-transform) is counted as marked.
        let mut sheet = build_sheet();
        let report = sheet
            .apply_axis_edit(GridAxisEdit::insert_rows(1, 1))
            .unwrap();
        assert_eq!(report.feature_regions_kept, 2);
        assert_eq!(report.feature_regions_dropped, 0);
        assert_eq!(report.feature_regions_marked_needs_refresh, 1);
        assert_eq!(report.merged_regions_kept, 1);
        assert_eq!(report.merged_regions_dropped, 0);
        assert_eq!(report.spill_facts_kept, 1);
        assert_eq!(report.spill_facts_dropped, 0);
        assert_eq!(sheet.table_overlays().len(), 1);
        assert_eq!(
            sheet.table_overlays().values().next().unwrap().table_range,
            rect(2, 1, 6, 3),
            "the table shifts down a row through the unified loop"
        );

        // An insert before row 2 intersects the pivot (rows 1-3): the edit is
        // refused fail-fast, before any overlay is mutated.
        let mut sheet = build_sheet();
        let before_tables = sheet.table_overlays().clone();
        let before_merged = sheet.merged_regions().to_vec();
        let before_features = sheet.feature_rendered_regions().to_vec();
        let err = sheet
            .apply_axis_edit(GridAxisEdit::insert_rows(2, 1))
            .unwrap_err();
        assert!(matches!(
            err,
            GridRefError::FeatureRenderedRegionEditRefused { .. }
        ));
        assert_eq!(
            sheet.table_overlays(),
            &before_tables,
            "a refused edit must not mutate tables"
        );
        assert_eq!(
            sheet.merged_regions(),
            before_merged.as_slice(),
            "a refused edit must not mutate merged regions"
        );
        assert_eq!(
            sheet.feature_rendered_regions(),
            before_features.as_slice(),
            "a refused edit must not mutate feature regions"
        );
    }

    #[test]
    fn compare_grid_overlay_blockage_detects_spill_fact_divergence() {
        let bounds = ExcelGridBounds {
            max_rows: 100,
            max_cols: 12,
        };
        let addr = |row, col| ExcelGridCellAddress::new("book:default", "sheet:default", row, col);
        let rect = |top, left, bottom, right| {
            GridRect::new(
                "book:default",
                "sheet:default",
                top,
                left,
                bottom,
                right,
                bounds,
            )
            .unwrap()
        };

        // Identical spill facts: the engines agree, no mismatch.
        let shared = GridSpillFact {
            anchor: addr(1, 1),
            extent: rect(1, 1, 4, 1),
            blocked: false,
        };
        assert!(
            compare_grid_overlay_blockage(
                std::slice::from_ref(&shared),
                std::slice::from_ref(&shared)
            )
            .is_empty()
        );

        // Same anchor, divergent blocked flag: one mismatch carrying both facts.
        let reference_fact = GridSpillFact {
            anchor: addr(1, 1),
            extent: rect(1, 1, 4, 1),
            blocked: false,
        };
        let optimized_fact = GridSpillFact {
            anchor: addr(1, 1),
            extent: rect(1, 1, 4, 1),
            blocked: true,
        };
        let mismatches = compare_grid_overlay_blockage(
            std::slice::from_ref(&reference_fact),
            std::slice::from_ref(&optimized_fact),
        );
        assert_eq!(mismatches.len(), 1);
        assert_eq!(mismatches[0].anchor, addr(1, 1));
        assert_eq!(mismatches[0].reference, Some(reference_fact));
        assert_eq!(mismatches[0].optimized, Some(optimized_fact));

        // Present in only one engine: a mismatch with the other side `None`.
        let only_optimized = GridSpillFact {
            anchor: addr(2, 1),
            extent: rect(2, 1, 3, 1),
            blocked: false,
        };
        let mismatches = compare_grid_overlay_blockage(&[], std::slice::from_ref(&only_optimized));
        assert_eq!(mismatches.len(), 1);
        assert_eq!(mismatches[0].reference, None);
        assert_eq!(mismatches[0].optimized, Some(only_optimized));
    }

