    #[test]
    fn optimized_grid_compact_oxfml_recalc_repairs_out_of_order_sequence_spill_consumer() {
        let mut sheet = optimized_sheet();
        sheet
            .set_formula(
                address(1, 1),
                GridFormulaCell::new("=SUM(B1#)", "excel.grid.v1:sum-late-spill:RC[1]#"),
            )
            .unwrap();
        sheet
            .set_formula(
                address(1, 2),
                GridFormulaCell::new("=SEQUENCE(3)", "excel.grid.v1:sequence:R1C2#"),
            )
            .unwrap();

        let report = sheet
            .run_engine_mode_with_oxfml(
                GridEngineMode::Both,
                [address(1, 1), address(1, 2), address(2, 2), address(3, 2)],
                100,
            )
            .expect("late B1# publication should repair its earlier consumer");

        assert!(report.mismatches.is_empty());
        let reference = report.reference.as_ref().unwrap();
        assert_eq!(reference.readout[0].computed, CalcValue::number(6.0));
        assert_eq!(reference.readout[1].computed, CalcValue::number(1.0));
        assert_eq!(reference.readout[2].computed, CalcValue::number(2.0));
        assert_eq!(reference.readout[3].computed, CalcValue::number(3.0));
        assert!(matches!(
            &reference.recalc,
            GridEngineRecalcReport::Reference(recalc)
                if recalc.p00_non_spill_exact_once_holds()
                    && recalc.spill_repair_passes == 1
                    && recalc.spill_repair_formula_evaluations == 2
                    && recalc.spill_repair_converged
                    && recalc.spill_facts_published == 1
                    && recalc.spill_ghost_cells_published == 2
        ));

        let optimized = report.optimized.as_ref().unwrap();
        assert_eq!(optimized.readout[0].computed, CalcValue::number(6.0));
        assert_eq!(optimized.readout[1].computed, CalcValue::number(1.0));
        assert_eq!(optimized.readout[2].computed, CalcValue::number(2.0));
        assert_eq!(optimized.readout[3].computed, CalcValue::number(3.0));
        assert!(matches!(
            &optimized.recalc,
            GridEngineRecalcReport::Optimized(recalc)
                if recalc.p00_primary_exact_once_holds()
                    && recalc.spill_repair_passes == 1
                    && recalc.spill_repair_formula_evaluations == 2
                    && recalc.spill_repair_converged
                    && recalc.spill_facts_published == 1
                    && recalc.spill_ghost_cells_published == 2
                    && recalc.computed_dense_value_regions == 1
                    && recalc.computed_sparse_cells == 1
        ));
    }

    #[test]
    fn grid_calc_ref_mark_all_spill_repair_settles_plain_consumer_of_late_settling_spill_chain() {
        // B5 coverage: address order A1 < B1 < C1 < D1 < E1, with A1 a
        // plain (non-`#`) scalar consumer of D1, and D1 itself a plain
        // scalar consumer of a later-addressed spill anchor E1 through
        // `#`. B1/C1 are an unrelated `#`-anchor/consumer pair whose only
        // job is to make `authored_contains_grid_spill_reference` true so
        // `repair_reference_spills_with_oxfml` actually runs (it is gated
        // off entirely for spill-free sheets).
        //
        // The effective-graph worklist already gates D1 on E1 and A1 on D1
        // by real precedent readiness, so this particular shape settles
        // within the ordinary worklist pass and the mandatory verification
        // repair pass changes nothing. It is kept as a direct regression
        // guard on the B5 convergence check (spill_facts-and-computed
        // stability, not spill_facts alone) for this address-order-vs-
        // dependency-order shape, backed by a mark-all-vs-dirty-recalc
        // differential below.
        let mut sheet = sheet();
        let a1 = address(1, 1);
        let b1 = address(1, 2);
        let c1 = address(1, 3);
        let d1 = address(1, 4);
        let e1 = address(1, 5);
        sheet
            .set_formula(
                a1.clone(),
                GridFormulaCell::new(
                    "=D1*10",
                    "excel.grid.v1:spill-repair-consumer:A1-D1-times-10",
                ),
            )
            .unwrap();
        sheet
            .set_formula(
                b1.clone(),
                GridFormulaCell::new(
                    "=SEQUENCE(2)",
                    "excel.grid.v1:spill-repair-consumer:B1-sequence",
                ),
            )
            .unwrap();
        sheet
            .set_formula(
                c1.clone(),
                GridFormulaCell::new(
                    "=SUM(B1#)",
                    "excel.grid.v1:spill-repair-consumer:C1-sum-B1-spill",
                ),
            )
            .unwrap();
        sheet
            .set_formula(
                d1.clone(),
                GridFormulaCell::new(
                    "=SUM(E1#)",
                    "excel.grid.v1:spill-repair-consumer:D1-sum-E1-spill",
                ),
            )
            .unwrap();
        sheet
            .set_formula(
                e1.clone(),
                GridFormulaCell::new(
                    "=SEQUENCE(2)",
                    "excel.grid.v1:spill-repair-consumer:E1-sequence",
                ),
            )
            .unwrap();

        let probe_sheet = sheet.clone();
        let report = sheet
            .recalculate_mark_all_dirty_with_oxfml()
            .expect("mark-all recalc with a late-settling spill-gated chain should succeed");

        // E1 spills {1;2} (rows 5,6 col 5); D1 = SUM(E1#) = 3; A1 = D1*10 = 30.
        assert_eq!(sheet.read_cell(&d1), CalcValue::number(3.0));
        assert_eq!(sheet.read_cell(&a1), CalcValue::number(30.0));
        assert_eq!(sheet.read_cell(&c1), CalcValue::number(3.0));
        assert!(report.spill_repair_converged);

        let diff = probe_sheet
            .run_dirty_recalc_differential_with_oxfml([GridDirtySeed::Cell(a1.clone())], [a1, d1])
            .expect("dirty-vs-mark-all differential should run for the settled spill chain");
        assert_dirty_differential_clean(&diff);
    }

