        assert_eq!(sheet.read_cell(&e2), CalcValue::number(17.0));
        assert!(
            sheet
                .runtime_dependency_graph()
                .axis_value_dependencies_for(&d2)
                .contains(&GridAxisValueDependency::columns(1, 2))
        );

        sheet
            .set_literal(b3.clone(), CalcValue::number(15.0))
            .unwrap();
