        let mut sheet = optimized_sheet();
        let global_range =
            GridRect::new("book:default", "sheet:default", 1, 1, 1, 1, bounds()).unwrap();
        let sheet_range =
            GridRect::new("book:default", "sheet:default", 2, 1, 2, 1, bounds()).unwrap();
